<script>
    // **NOTE: Updated to 100 questions as requested**
    const TOTAL_QUESTIONS = 100; 

    // Event listener for form submission
    document.getElementById('quiz-form').addEventListener('submit', function(event) {
        event.preventDefault();
        submitQuiz();
    });

    function submitQuiz() {
        let correctCount = 0;
        let unansweredCount = 0;

        // Iterate through all 100 questions
        for (let i = 1; i <= TOTAL_QUESTIONS; i++) {
            const questionName = `q${i}`;
            const explanationBox = document.getElementById(`exp${i}`);
            const options = document.getElementsByName(questionName);
            let isAnswered = false;

            // Find the selected option and check if it is correct
            for (const option of options) {
                if (option.checked) {
                    isAnswered = true;

                    if (option.getAttribute('data-correct') === 'true') {
                        correctCount++;
                        explanationBox.className = 'explanation correct';
                        explanationBox.innerHTML = `<strong>Correct! ✅</strong><br>` + explanationBox.querySelector('.explanation-content').innerHTML;
                    } else {
                        explanationBox.className = 'explanation incorrect';
                        let correctAnswerText = document.querySelector(`input[name="${questionName}"][data-correct="true"]`).parentNode.textContent.trim();
                        explanationBox.innerHTML = `<strong>Incorrect. ❌ The correct term is: ${correctAnswerText}</strong><br>` + explanationBox.querySelector('.explanation-content').innerHTML;
                    }

                    // Show the explanation box
                    explanationBox.style.display = 'block';

                    // Disable all radio buttons after submission
                    options.forEach(opt => opt.disabled = true);
                    break;
                }
            }

            if (!isAnswered) {
                unansweredCount++;
                // Still show the correct answer for unanswered questions
                const explanationBox = document.getElementById(`exp${i}`);
                explanationBox.className = 'explanation incorrect';
                let correctAnswerText = document.querySelector(`input[name="${questionName}"][data-correct="true"]`).parentNode.textContent.trim();
                explanationBox.innerHTML = `<strong>Unanswered. ❌ The correct term is: ${correctAnswerText}</strong><br>` + explanationBox.querySelector('.explanation-content').innerHTML;
                explanationBox.style.display = 'block';
                options.forEach(opt => opt.disabled = true);
            }
        } 

        // Calculate and display results
        const finalScore = (correctCount / TOTAL_QUESTIONS) * 100;

        document.getElementById('total-questions').textContent = TOTAL_QUESTIONS;
        document.getElementById('correct-answers').textContent = correctCount;
        document.getElementById('final-score').textContent = `${finalScore.toFixed(2)}%`;

        document.getElementById('results').style.display = 'block';
        document.getElementById('submit-btn').disabled = true;
        document.getElementById('submit-btn').textContent = 'Quiz Submitted';
    }
</script>


