      ) : (
        <div className="flex flex-col items-center justify-center p-12 bg-white border-2 border-dashed border-slate-200 rounded-xl text-center w-full max-w-lg">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
            <Filter className="text-slate-300" size={32} />
          </div>
          <h3 className="text-lg font-bold text-slate-800 mb-2">No cards found</h3>
          <p className="text-slate-500 text-sm mb-6">Try selecting different topics or clear your filters.</p>
          <Button variant="outline" onClick={() => setSelectedCategories([])}>
            Clear Filters
          </Button>
